import math
from typing import List

class Solution:
    def repairCars(self, ranks: List[int], cars: int) -> int:
        left = 0
        min_rank = min(ranks)
        right = min_rank * cars * cars

        def check_time(t):
            total = 0
            for r in ranks:
                total += math.isqrt(t // r)
                if total >= cars:
                    return True
            return total >= cars

        while left < right:
            mid = (left + right) // 2
            if check_time(mid):
                right = mid
            else:
                left = mid + 1
        return left
